VALUES
  ('cpa-moex-00161', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'essay', 'A公司目前有兩家劇場：甲劇場和乙劇場。八月份，A公司的稅前營
業淨利為$30,000，銷貨收入為$450,000。甲劇場的邊際貢獻為
$100,000，占其銷貨收入的 40%；而乙劇場的部門毛利（segment
margin）為$30,000，占其銷貨收入的 15%。甲劇場的可追溯固定費用
（traceablefixed expenses）為$60,000，乙劇場的則為$40,000。
試作：（必須列示計算過程，否則不予計分）
乙劇場的邊際貢獻率為何？（4 分）
甲劇場和乙劇場合計總變動成本為何？（4分）
A公司的固定成本（totalfixedexpenses）總額為何？（6分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00162', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關全部成本法與變動成本法，下列敘述何者正確？', '["全部成本法又稱為直接成本法，變動成本法又稱為歸納成本法", "變動成本法將直接材料、直接人工、變動製造費用計入產品成本中", "全部成本法將直接材料、直接人工、製造費用、行銷管理費用等計入產品成本中", "依照變動成本法編製的財務報表主要為提供給企業外部使用者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00163', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產多種鋼鐵產品，若以自動化生產之熱軋鋼板為成本標的，則A公司的生產部門主 管薪資應屬何種成本類型？', '["期間成本（periodcost）", "直接製造成本（directmanufacturingcost）", "製造費用（manufacturingoverhead）", "主要成本（primecost）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00164', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產過程中，使用直接原料$1,500,000及間接原料$357,000，直接人工成本為$688,000， 另有$125,000間接人工成本，其他製造費用共計$900,000，A公司主要成本（prime cost）及 加工成本（conversioncost）分別為何？', '["主要成本$2,545,000、加工成本$2,070,000", "主要成本$2,670,000、加工成本$900,000", "主要成本$2,188,000、加工成本$2,070,000", "主要成本$2,188,000、加工成本$1,382,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00165', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司的資料如下： 售價$50，每單位變動成本： 直接原料$12 直接製造人工$2.5 製造費用$0.5 銷售費用$5 每年的固定成本$200,000 公司銷售25,000單位商品，變動成本占總成本的比例？', '["27.68%", "40%", "53.57%", "71.43%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00166', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司有甲、乙兩個生產部門，此二部門X1年的製造成本預算為： 甲生產部門 乙生產部門 直接原料 $725,000 $150,000 直接人工 $240,000 $918,000 製造費用 $480,000 $400,000 A 公司生產批號 605 產品時，實際發生成本有直接原料$30,000，甲生產部門直接人工成本 $8,000及乙生產部門直接人工成本$16,000。A公司依據年初決定之部門費率，按直接人工成 本將製造費用分攤至各生產批次。甲生產部門的製造費用分攤率是多少？', '["50.00%", "75.99%", "131.59%", "200.00%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00167', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司生產芝麻相關產品，先將芝麻原料經過一聯合加工過程，聯合成本$1,200,000，在分離 點產出芝麻粉與芝麻油二種聯合產品。為因應消費者養生趨勢，A公司考慮是否將此二產品 進一步加工為養生概念產品再出售。該公司彙整相關資訊如下： 芝麻粉 芝麻油 生產量（公斤） 50,000 30,000 分離點售價 每公斤$45 每公斤$156 分離點後進一步加工售價 每公斤$63 每公斤$174 分離成本 $384,000 $600,000 若A公司採用分離點售價法分攤聯合成本，下列何者正確？', '["芝麻粉與芝麻油皆應進一步加工", "芝麻粉與芝麻油皆不應進一步加工", "芝麻粉應進一步加工；芝麻油不應進一步加工", "芝麻粉不應進一步加工；芝麻油應進一步加工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00168', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A公司製造無人機，使用加權平均法之分步成本制；X1年期初在製品存貨$129,000，期末在 製品存貨$145,500，期初存料$150,000，本期購料$440,000，直接人工成本$335,000，變動製 造費用$365,000，固定製造費用$545,000，當期產出的製成品成本$1,695,000，期初製成品 $565,000，期末製成品$455,000。A公司X1年之本期用料為多少？', '["$421,500", "$436,500", "$450,500", "$466,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00169', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關預算規劃，下列敘述何者錯誤？', '["預算之功能之一為協助組織有效地達成營運目標", "營業預算為針對未來營業收支之規劃，財務預算為針對未來資金籌措及運用之規劃", "營業預算主要目的為規劃資金收支、編列現金預算及預計資產負債表", "資本預算主要是涉及不動產、廠房、設備之投資規劃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00170', 'cpa', 'cpa-moex-113-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'A麵包公司產銷油炸麵包和餐包二種產品，該公司採用作業成本制（operationcosting），二產 品加工過程相近但僅油炸麵包需要使用油炸作業。X1年預計使用的產量、直接原料成本及加 工作業方式如下： 油炸麵包 餐包 產量（個） 54,600 11,700 直接原料成本 $4,290,000 $7,215,000 加工作業方式：（成本動因為產量）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:00+00:00", "source_pdf_sha1": "af3bae8545fa", "answer_pdf_sha1": "89339de3aa42", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
